import time
import requests
from typing import Optional, Dict, Any


class HttpClient:
    def __init__(self, base_url: str, timeout: int = 30, max_retries: int = 3):
        self.base_url = base_url
        self.timeout = timeout
        self.max_retries = max_retries

    def _request_with_retry(self, method: str, url: str, **kwargs) -> requests.Response:
        last_error = None
        for attempt in range(self.max_retries):
            try:
                response = requests.request(method, url, timeout=self.timeout, **kwargs)
                if response.status_code < 500:
                    return response
                last_error = Exception(f'Server error: {response.status_code}')
            except requests.ConnectionError as e:
                last_error = e
            if attempt < self.max_retries - 1:
                time.sleep(2 ** attempt * 0.1)  # 0.1s, 0.2s, 0.4s
        raise last_error

    def get(self, path: str, params: Optional[Dict] = None) -> requests.Response:
        return self._request_with_retry('GET', f'{self.base_url}{path}', params=params)

    def post(self, path: str, data: Any = None) -> requests.Response:
        return self._request_with_retry('POST', f'{self.base_url}{path}', json=data)
